var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"이야, 깜짝 놀랐습니다.","JPN":"いやあ、ビックリしたっすよ。","ENG":"Whoa, that startled me.","TWN":"哎呀，嚇死我了。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"바다 한복판이 번쩍 하더니, 거기서 사람이 떨어질 거라곤 꿈에도 몰랐거든요.","JPN":"海のど真ん中がピカーっと光ったと思ったら、人が落ちてきたっしょ？　そんなこと夢にも思わねぇっすから。","ENG":"The sea suddenly flashed out in the middle of nowhere, and I never imagined people would come falling out of it.","TWN":"海中央突然有閃光，作夢都沒想到會有人從裡面掉下來。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마침 배가 근처에 있어서 살았어요. 저희 중 한 명이 수영을 전혀 못 하거든요.","JPN":"ちょうど近くに船があって助かったよ。一人、全然泳げない人がいたから。","ENG":"Lucky for us your boat was nearby. One of us can't swim at all.","TWN":"我們之中有人完全不會游泳，幸好船就在附近才得救。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"말했다시피 우린 훈련 중인 카운터다. 이 녀석의 공간이동 능력을 함께 시험하다 이렇게 됐지.","JPN":"さっきも話したように、私たちは訓練中のカウンターだ。こいつの空間移動能力をテストしていたらこうなった。","ENG":"Like I said, we're Counters in training. We were testing this one's teleportation ability together when it happened.","TWN":"就像之前說的，我們是在訓練中的制裁者。在測試這傢伙的空間移動能力時才變成這樣。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 제가요?","JPN":"え？　私ですか？","ENG":"Huh? Me?","TWN":"欸？我嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으악! 네, 넵! 전 공간이동 능력을 쓰는 카운터 훈련생입니닷! 제 실력이 미흡해서 시민 분께 신세를 졌습니다!","JPN":"わあっ！　は、はい！　私は空間移動能力を使うカウンター訓練生です！　私の実力が足りなくて、市民の方にご迷惑をおかけしました！","ENG":"Aah! O-okay! I'm a Counter trainee with teleportation abilities! My skills weren't up to par, so we ended up troubling a civilian!","TWN":"啊！是、是的！我是使用空間移動能力的制裁者訓練生！因為我實力不足，才會麻煩您！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"공간이동이라니 신기하네요. 능력을 쓸 때는 특별한 포즈 같은 거라도 취하나요?","JPN":"空間移動なんて不思議っすね。能力を使う時には、特別なポーズを取ったりするんすか？","ENG":"Teleportation, huh? That's amazing. Do you strike some kind of special pose when you use it?","TWN":"空間移動啊，真神奇。使用能力時會擺什麼特別姿勢嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 어... 음...","JPN":"えっ？　あ……えーっと……","ENG":"Huh? Uh... um...","TWN":"欸？呃……嗯……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이렇게, 눈을 감고 정신을 집중하면서...","JPN":"こうやって、目を閉じて精神を集中しながら……","ENG":"Like this, I close my eyes and focus...","TWN":"像這樣，閉上眼睛集中精神……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"두 손가락을 펼쳐 이마 중심을 가리킵니다!","JPN":"指を伸ばして額の中心に当てます！","ENG":"Then put two fingers at the center of my forehead!","TWN":"然後伸出兩根手指，指向額頭中央！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"오, 그럴싸 한데?","JPN":"おお、それっぽい。","ENG":"Oh, that actually looks convincing.","TWN":"哦，挺像回事的呢？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"하하, 멋지기 보단 귀엽네요.","JPN":"はは、カッコいいというより可愛いっすね。","ENG":"Haha, more cute than cool.","TWN":"哈哈，比起帥氣更可愛呢。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"생각보다 어린 친구들이라 놀랐어요. 뉴스로 소식은 들었는데, 초능력자들이 우리 사회에 그렇게 많았다는 사실이 아직은 좀 낯설기도 하고요.","JPN":"それにしても、思ったより若くてビックリしたっすよ。ニュースで聞いてはいたけど、超能力者がこの社会にそんなに多かったなんて、まだ実感が湧かねぇっす。","ENG":"I'm surprised you're younger than I expected. I heard about it on the news, but it's still a little strange getting used to the fact that there are so many people with superpowers in our society.","TWN":"沒想到你們這麼年輕。雖然新聞有報導，但還是不太習慣社會上有這麼多超能力者。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"여러분도 다른 카운터 분들처럼 관리국에 들어가기 위해 훈련하고 계신 거죠?","JPN":"皆さんも他のカウンターみたく管理局に入るために訓練してるんすよね？","ENG":"You're training to join the Administration like the other Counters, right?","TWN":"你們也像其他制裁者一樣，為了進入管理局在訓練吧？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 마침 오늘 그라운드 원에 공인 선발 시험이 있어서 하루 묵을 알아보던 중이었다.","JPN":"ああ。ちょうど今日グラウンド・ワンで公認選抜試験があって、一晩泊れるところを探していたんだ。","ENG":"That's right. There was an official audition at Ground One today, so we were looking for somewhere to stay the night.","TWN":"對。剛好今天在G1有正式選拔考試，我們正打算找地方住一晚。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"그라운드 원... 그렇죠. 벌써 다들 그런 이름으로 부르는군요.","JPN":"グラウンド・ワン……そうっすか。もうみんなその名前で呼んでるんすね。","ENG":"Ground One... right. Everyone's already calling it that.","TWN":"G1啊……也對，現在大家都這麼叫了呢。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"하긴, 저 대균열이라는 것이 도시를 집어삼킨 뒤로는 완전히 다른 곳이 됐으니까요.","JPN":"まあ、あの大亀裂っちゅうのが都市を飲み込んでからは、完全に別の場所になっちまったっすから。","ENG":"Well, once that Grand Dimension Crevice swallowed up the city, it really did become a completely different place.","TWN":"畢竟自從大峽谷吞噬城市之後，這裡已經完全變成另一個地方了。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"그래도 다행이에요.","JPN":"でも、よかったっす。","ENG":"Still, it's a relief.","TWN":"不過真是萬幸。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"그땐 세상이 다 끝나는 줄 알았는데, 관리국 덕에 다시 사람이 살 수 있는 곳이 되어가고 있다는 게 느껴지거든요.","JPN":"当時は世界が終わると思ったっすけど、管理局のおかげでまただんだん人が住める場所になっている気がするっすよ。","ENG":"Back then, I thought the world was over, but thanks to the Administration, it feels like it's becoming a place people can live in again.","TWN":"當時我以為世界真的要滅亡了。但現在我能感覺到在管理局的努力下，這裡正重新變成能讓人生活的地方。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"아마... 이런 식으로 20년 정도만 지나면, 아무 걱정 없던 다시 원래의 삶으로 돌아가 있겠죠?","JPN":"たぶん……こんな感じで20年くらい経てば、何の心配もなかった元の生活に戻れるんじゃないっすかね。","ENG":"Maybe... if another twenty years pass like this, we'll be back to our old lives without a single worry, don't you think?","TWN":"大概……再過20年左右，大家就能回到以前那種毫無煩惱的生活吧？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어... 그건...","JPN":"え……それは……","ENG":"Uh... well...","TWN":"呃……那個……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 그럴 거야.","JPN":"うん、そうだよ。","ENG":"Yeah, us too.","TWN":"嗯，一定會的。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우리가 그렇게 되도록 만들 테니까.","JPN":"私たちがそうなるようにするから。","ENG":"We'll make sure it happens.","TWN":"我們會讓它實現。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"...고마워요. 든든하네요.","JPN":"……ありがてえ。心強いっす。","ENG":"...Thank you. That's reassuring.","TWN":"……謝謝，聽你這麼說真讓人安心。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"여기서 좀 더 가시면 관리국에서 마련한 캠프가 있습니다.","JPN":"ここからもう少し行ったところに、管理局が建てたキャンプがあるっす。","ENG":"If you go a little farther from here, there's a camp the Administration set up.","TWN":"再往前走一點，就有管理局設立的營地。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"호텔은 아니지만, 하루 묵어가기엔 부담 없을 거에요. 관리국 직원 분들도 많이 계시거든요.","JPN":"ホテルじゃないが、一晩泊るには問題ないはずっす。管理局職員もたくさんいるし。","ENG":"It's not a hotel, but it's a fine place to stay for a night. There are plenty of Administration staff there too.","TWN":"雖然不是飯店，但住一晚沒問題。那裡也有很多管理局的人。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기까지 안내해줘서 고마워, 아저씨.","JPN":"ここまで案内してくれてありがとう、おじさん。","ENG":"Thanks for showing us the way, mister.","TWN":"謝謝你帶我們到這裡，大叔。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};